import React, { useState } from 'react';
import Header from '../components/header/header';
import Footer from '../components/Footer/Footer';
import { useResolved, ResolvedContentProvider } from '../ppm/util/ResolvedContentContext';
import '../global.css';

const GalleryCardContent: React.FC<{ item: any }> = ({ item }) => (
  <>
    <div className="media-thumb">
      {item.image ? (
        <img src={item.image} alt={item.title} />
      ) : (
        <div className="placeholder-thumb gallery-placeholder">
          <span>📷</span>
        </div>
      )}
    </div>
    <div className="media-info">
      <p className="item-label">{item.category || (item.type === 'collection' ? 'Bộ sưu tập' : 'Hình ảnh')}</p>
      <h3>{item.title}</h3>
    </div>
  </>
);

const GalleriesPageInner = () => {
  const resolved = useResolved();
  const galleryData = resolved.pages.galleriesPage;
  const [visibleCount, setVisibleCount] = useState(12);
  const [searchQuery, setSearchQuery] = useState('');

  // Handle hash navigation
  React.useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash;
      if (hash) {
        const mapping: {[key:string]: string} = {
          '#su-kien': 'Sự kiện',
          '#dai-hoi': 'Đại hội',
          '#2026': '2026',
          '#khai-giang': 'Khai Giảng'
        };
        const searchVal = mapping[hash.toLowerCase()];
        if (searchVal) {
          setSearchQuery(searchVal);
          // Scroll to grid
          const grid = document.querySelector('.media-grid');
          if (grid) grid.scrollIntoView({ behavior: 'smooth', block: 'start' });
        }
      }
    };
    handleHash();
    window.addEventListener('hashchange', handleHash);
    return () => window.removeEventListener('hashchange', handleHash);
  }, []);

  // Helper to extract first image from HTML body if no explicit thumbnail exists
  const extractFirstImage = (body: string) => {
    if (!body) return null;
    // Try to find high-res image link in anchor tags first
    const hrefMatch = body.match(/<a[^>]+href=["']([^"']+\.(?:jpg|jpeg|png|gif|webp))["']/i);
    if (hrefMatch) return hrefMatch[1];
    // Fallback to img src
    const imgMatch = body.match(/<img[^>]+src=["']([^"']+)["']/i);
    return imgMatch ? imgMatch[1] : null;
  };

  // Combine both collections and image blogs
  const allGalleries = [
    ...(galleryData.collections || []).map((item: any) => ({
      ...item,
      type: 'collection',
      image: item.image || extractFirstImage(item.body)
    })),
    ...(galleryData.imageBlogs || []).map((item: any) => ({
      ...item,
      type: 'image-blog',
      image: item.image || extractFirstImage(item.body)
    }))
  ];

  const filteredGalleries = allGalleries.filter(item => {
    if (!searchQuery) return true;
    const q = searchQuery.toLowerCase();
    return (item.title || '').toLowerCase().includes(q) || ((item as any).category || '').toLowerCase().includes(q);
  });

  const displayedGalleries = filteredGalleries.slice(0, visibleCount);

  return (
    <div className="media-page">
      <Header />
      <div style={{ height: '60px' }} />

      <main className="media-container">
        <header className="media-header">
          <h1>{galleryData.sectionTitle || 'Thư viện Hình ảnh & Sự kiện'}</h1>
          <div className="search-bar-container">
            <input
              type="text"
              placeholder="Tìm kiếm hình ảnh hoặc sự kiện..."
              value={searchQuery}
              onChange={(e) => {
                setSearchQuery(e.target.value);
                setVisibleCount(12); // reset count on text change
              }}
              className="gallery-search-input"
            />
          </div>
        </header>

        <div className="media-grid">
          {displayedGalleries.map((item: any, idx) => {
            const linkTo = item.link || (item.slug ? `/collection/${item.slug}` : null);
            if (!linkTo) {
              return (
                <div key={`${item.id}-${idx}`} className="media-card gallery-card no-link">
                  <GalleryCardContent item={item} />
                </div>
              );
            }
            return (
              <a key={`${item.id}-${idx}`} href={linkTo} className="media-card gallery-card">
                <GalleryCardContent item={item} />
              </a>
            );
          })}
        </div>

        {visibleCount < filteredGalleries.length && (
          <div className="load-more-container">
            <button
              className="load-more-btn"
              onClick={() => setVisibleCount(prev => prev + 12)}
            >
              Xem thêm nội dung
            </button>
          </div>
        )}
      </main>

      <Footer />

      <style dangerouslySetInnerHTML={{
        __html: `
        .media-page {
          background-color: #f5f3ee;
          min-height: 100vh;
        }
        .media-container {
          max-width: 1200px;
          margin: 0 auto;
          padding: 40px 20px;
        }
        .media-header {
          margin-bottom: 40px;
          border-bottom: 2px solid #E6B422;
          padding-bottom: 20px;
          display: flex;
          justify-content: space-between;
          align-items: center;
          flex-wrap: wrap;
          gap: 20px;
        }
        .media-header h1 {
          font-family: 'Playfair Display', serif;
          color: #1a1a1a;
          margin: 0;
        }
        .search-bar-container {
          flex: 1;
          min-width: 250px;
          max-width: 400px;
          display: flex;
          justify-content: flex-end;
        }
        .gallery-search-input {
          width: 100%;
          padding: 12px 20px;
          border-radius: 30px;
          border: 1px solid rgba(0,0,0,0.1);
          background: #fff;
          font-family: 'Inter', sans-serif;
          font-size: 15px;
          box-shadow: inset 0 2px 4px rgba(0,0,0,0.02);
          transition: all 0.3s ease;
        }
        .gallery-search-input:focus {
          outline: none;
          border-color: #E6B422;
          box-shadow: 0 0 0 3px rgba(230, 180, 34, 0.2);
        }
        .media-grid {
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
          gap: 30px;
        }
        .gallery-card {
          background: white;
          border-radius: 12px;
          overflow: hidden;
          box-shadow: 0 4px 15px rgba(0,0,0,0.05);
          transition: all 0.3s ease;
          text-decoration: none;
          display: block;
        }
        .gallery-card:hover {
          transform: translateY(-8px);
          box-shadow: 0 12px 30px rgba(0,0,0,0.1);
        }
        .media-thumb {
          aspect-ratio: 3/2;
          background: #eee;
          overflow: hidden;
        }
        .media-thumb img {
          width: 100%;
          height: 100%;
          object-fit: cover;
          transition: transform 0.5s ease;
        }
        .gallery-card:hover img {
          transform: scale(1.1);
        }
        .gallery-placeholder {
          display: flex;
          align-items: center;
          justify-content: center;
          font-size: 50px;
          height: 100%;
        }
        .media-info {
          padding: 20px;
        }
        .item-label {
          margin: 0 0 8px 0;
          font-size: 11px;
          color: #E6B422;
          font-weight: 700;
          letter-spacing: 1.5px;
          text-transform: uppercase;
        }
        .media-info h3 {
          margin: 0;
          font-size: 18px;
          color: #1a1a1a;
          font-family: 'Playfair Display', serif;
          line-height: 1.4;
        }
        .load-more-container {
          display: flex;
          justify-content: center;
          margin-top: 50px;
          padding-bottom: 20px;
        }
        .load-more-btn {
          background-color: #E6B422;
          color: white;
          border: none;
          padding: 14px 40px;
          border-radius: 30px;
          font-size: 16px;
          font-weight: 600;
          font-family: 'Inter', sans-serif;
          cursor: pointer;
          transition: all 0.3s ease;
          box-shadow: 0 4px 15px rgba(230, 180, 34, 0.3);
        }
        .load-more-btn:hover {
          background-color: #d4a31d;
          transform: translateY(-2px);
          box-shadow: 0 6px 20px rgba(230, 180, 34, 0.4);
        }
      `}} />
    </div>
  );
};

const GalleriesPage = () => (
  <ResolvedContentProvider>
    <GalleriesPageInner />
  </ResolvedContentProvider>
);

export default GalleriesPage;
